import{_ as t,o as a,c as i,ae as o}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Test Ads Campaign Setup","description":"","frontmatter":{"title":"Test Ads Campaign Setup","slug":"testing-ads-campaign-setup"},"headers":[],"relativePath":"marketer-hub/testing-ads-campaign-setup.md","filePath":"marketer-hub/testing-ads-campaign-setup.md"}'),r={name:"marketer-hub/testing-ads-campaign-setup.md"};function n(s,e,d,l,p,c){return a(),i("div",null,[...e[0]||(e[0]=[o('<h2 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h2><p>Before testing, make sure of the following:</p><ul><li>The <a href="./native-sdks-overview.html">Branch SDK</a> is implemented in your app.</li><li><a href="./configure-default-link-behaviors.html">Default link behavior</a> and attribution windows are configured.</li><li><a href="./ad-partners-list.html">Ads Partners</a> are enabled.</li></ul><h2 id="_1-add-a-test-device" tabindex="-1">1. Add a Test Device <a class="header-anchor" href="#_1-add-a-test-device" aria-label="Permalink to &quot;1. Add a Test Device&quot;">​</a></h2><p>Before you complete the steps below, we highly recommend <a href="./add-test-devices.html">adding your test device</a> to your Branch account. This enables you to repeatedly test installing your app without affecting real traffic and attribution.</p><div class="info custom-block"><p class="custom-block-title">Note</p><p>If you’re on the New Branch experience, read our <a href="https://help.branch.io/docs/add-and-manage-test-devices-new" target="_blank" rel="noreferrer">Add and Manage Test Devices (New)</a> article.</p></div><h2 id="_2-create-a-branch-link" tabindex="-1">2. Create a Branch Link <a class="header-anchor" href="#_2-create-a-branch-link" aria-label="Permalink to &quot;2. Create a Branch Link&quot;">​</a></h2><p>Please follow the <a href="./ad-links.html">Creating Ad Links</a> instructions.</p><p>To ensure your ad link template itself works properly for testing, please make sure the created ad link template passes the initial validation check before using.</p><p>Your Branch Ad Link should look similar to the following (but will vary depending on your selected ad partner) :</p><p><code>https://branchster.app.link/Y2E3bNSaCX?%243p=a_youappi&amp;%24aaid=&lt;&gt;&lt;&gt;&lt;&gt;&lt;&gt;&lt;&gt;&lt;&gt;&lt;&gt;&lt;&gt;</code></p><h2 id="_3-pass-in-required-link-data-via-macros" tabindex="-1">3. Pass in Required Link Data via Macros <a class="header-anchor" href="#_3-pass-in-required-link-data-via-macros" aria-label="Permalink to &quot;3. Pass in Required Link Data via Macros&quot;">​</a></h2><p>As you are testing the link yourself - rather than it being used by your Ad Partner for a live campaign - you will need to manually pass in the relevant values for proper attribution and Postbacks.</p><p>In order to test your Branch link for both routing and attribution, you must ensure you&#39;ve supplied<br><strong>real Device IDs - AAID for Android devices and IDFA for Apple devices</strong>. If you don&#39;t supply the device IDs from your testing devices, Branch will use point in time modeling for probabilistic attribution.</p><div class="info custom-block"><p class="custom-block-title">How Do I Find my Device IDs?</p><p>Learn how to find your Android and/or iOS device IDs <a href="./how-do-i-find-my-device-ids.html">here</a>.</p></div><p>Using the sample Branch Ad Link above, filling in the macros would result in the following link:</p><p><code>https://branchster.app.link/Y2E3bNSaCX?%243p=a_youappi&amp;%24aaid=38400000-8cf0-11bd-b23e-10b96e40000d&amp;%24idfa=00000000-0000-0000-0000-000000000000&amp;trackertoken=1234&amp;ya_reen_id=2345&amp;~campaign=my_test_campaign&amp;~campaign_id=9876&amp;~click_id=1111&amp;~secondary_publisher=45678</code></p><p>For a complete list of the macros that Branch supports in postbacks, please see <a href="./postback-macros-functions.html">Postback Macros &amp; Functions</a>.</p><div class="warning custom-block"><p class="custom-block-title">Not Passing Data</p><p>Leaving the macros in the link - e.g. <code>&lt;&gt;</code> - will result in broken links and therefore will not work. You can pass in empty values for the link to work, but the subsequent postbacks will return empty values to your partner.</p></div><h3 id="common-ad-link-status-scenarios" tabindex="-1">Common Ad Link Status Scenarios <a class="header-anchor" href="#common-ad-link-status-scenarios" aria-label="Permalink to &quot;Common Ad Link Status Scenarios&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Link Status</th><th>Reason</th><th>Sample Test Link</th></tr></thead><tbody><tr><td><strong>Client side</strong></td><td></td><td></td></tr><tr><td>Working</td><td>Filled out one device ID, left the other blank</td><td><code>https://branchster.app.link/Y2E3bNSaCX?%243p=a_youappi&amp;%24aaid=&amp;%24idfa=6D92078A-8246-4BA4-AE5B-76104861E7DC&amp;trackertoken=&lt;&gt;&lt;&gt;&lt;&gt;&lt;&gt;&lt;&gt;&lt;&gt;</code></td></tr><tr><td>Working</td><td>Not S2S, specified both AAID &amp; IDFA (OS is figured out from the client)</td><td><code>https://branchster.app.link/Y2E3bNSaCX?%243p=a_youappi&amp;%24aaid=38400000-8cf0-11bd-b23e-10b96e40000d&amp;%24idfa=6D92078A-8246-4BA4-AE5B-76104861E7DC&amp;trackertoken=%3Ctrackertoken%3E&amp;ya_reen_id=%3Cya_reen_id%3E&amp;~campaign=%3Ccampaignname%3E&amp;~campaign_id=%3Ccampaignid%3E&amp;~click_id=%3Cparams%3E&amp;~secondary_publisher=%3Cpublisherid%3E</code></td></tr><tr><td>Broken</td><td>Clicked raw link directly from UI (Device IDs not passed in)</td><td><code>https://branchster.app.link/Y2E3bNSaCX?%243p=a_youappi&amp;%24aaid=&lt;&gt;&lt;&gt;&lt;&gt;&lt;&gt;&lt;&gt;&lt;&gt;&lt;&gt;&gt;&gt;</code></td></tr><tr><td>Broken</td><td>Left both device ID macros in without filling them out</td><td><code>https://branchster.app.link/Y2E3bNSaCX?%243p=a_youappi&amp;%24aaid=&lt;&gt;&lt;&gt;&lt;&gt;&lt;&gt;&lt;&gt;&lt;&gt;&lt;&gt;&gt;&gt;</code></td></tr><tr><td>Broken</td><td>Filled out one device ID, left the other one as a macro</td><td><code>https://branchster.app.link/Y2E3bNSaCX?%243p=a_youappi&amp;%24aaid=&lt;&gt;&lt;&gt;&lt;&gt;&lt;&gt;&lt;&gt;&lt;&gt;&gt;&gt;</code></td></tr><tr><td><strong>Server to server ($s2s=true)</strong></td><td></td><td></td></tr><tr><td>Working</td><td>S2S with a device ID (doesn&#39;t redirect, by design, as it&#39;s server to server)</td><td><code>https://branchster.app.link/Y2E3bNSaCX?%243p=a_youappi&amp;%24aaid=&amp;%24idfa=6D92078A-8246-4BA4-AE5B-76104861E7DC&amp;trackertoken=%3Ctrackertoken%3E&amp;ya_reen_id=%3Cya_reen_id%3E&amp;~campaign=%3Ccampaignname%3E&amp;~campaign_id=%3Ccampaignid%3E&amp;~click_id=%3Cparams%3E&amp;~secondary_publisher=%3Cpublisherid%3E&amp;$s2s=true&amp;user_agent={user_agent}&amp;device_ip={ip_address}</code></td></tr><tr><td>Broken</td><td>Clicked raw link directly from UI</td><td><code>https://branchster.app.link/Y2E3bNSaCX?%243p=a_youappi&amp;%24aaid=&lt;&gt;&lt;&gt;&lt;&gt;&lt;&gt;&lt;&gt;&lt;&gt;&lt;&gt;&gt;&gt;</code></td></tr><tr><td>Broken</td><td>Has a $S2S param but didn&#39;t provide a device ID</td><td><code>https://branchster.app.link/Y2E3bNSaCX?%243p=a_youappi&amp;%24aaid=&amp;%24idfa=&amp;trackertoken=%3Ctrackertoken%3E&amp;ya_reen_id=%3Cya_reen_id%3E&amp;~campaign=%3Ccampaignname%3E&amp;~campaign_id=%3Ccampaignid%3E&amp;~click_id=%3Cparams%3E&amp;~secondary_publisher=%3Cpublisherid%3E&amp;$s2s=true&amp;user_agent={user_agent}&amp;device_ip={ip_address}</code></td></tr><tr><td>Broken</td><td>S2S, specified both AAID &amp; IDFA (means we can&#39;t figure out the OS)</td><td><code>https://branchster.app.link/Y2E3bNSaCX?%243p=a_youappi&amp;%24aaid=38400000-8cf0-11bd-b23e-10b96e40000d&amp;%24idfa=6D92078A-8246-4BA4-AE5B-76104861E7DC&amp;trackertoken=%3Ctrackertoken%3E&amp;ya_reen_id=%3Cya_reen_id%3E&amp;~campaign=%3Ccampaignname%3E&amp;~campaign_id=%3Ccampaignid%3E&amp;~click_id=%3Cparams%3E&amp;~secondary_publisher=%3Cpublisherid%3E&amp;$s2s=true&amp;user_agent={user_agent}&amp;device_ip={ip_address}</code></td></tr></tbody></table><h2 id="_4-perform-a-click-download-app" tabindex="-1">4. Perform a Click &amp; Download App <a class="header-anchor" href="#_4-perform-a-click-download-app" aria-label="Permalink to &quot;4. Perform a Click &amp; Download App&quot;">​</a></h2><p>To test the Branch Ad Link and appropriate routing, email yourself the Ad link. On your device, open the email and click the link (or ad that embeds it). If you&#39;re testing on your office Wifi, we recommend turning Wifi off and using LTE/Cell to ensure we get a unique fingerprint of your device.</p><p>This click should redirect you through the Branch system to the appropriate app store and/or destination where you can download your app.</p><p>Open the app so that Branch captures your device information and matches the install event with the click event.</p><div class="warning custom-block"><p class="custom-block-title">Troubleshooting Link Formatting Issues</p><p>If the link is not correctly formatted or is missing key identifiers, Branch is unable to complete appropriate routing and attribution.</p><p>Please see <a href="./troubleshooting-link-formatting-errors.html">Troubleshooting Link Formatting Issues</a> for possible causes and solutions.</p></div><h2 id="_5-check-liveview-for-associated-actions" tabindex="-1">5. Check Liveview for Associated Actions <a class="header-anchor" href="#_5-check-liveview-for-associated-actions" aria-label="Permalink to &quot;5. Check Liveview for Associated Actions&quot;">​</a></h2><p>Liveview allows you to validate and debug your setup by including advanced filtering that allows you to restrict down to specific events (i.e. clicks, installs, purchases) as well as webhook/postback records.</p><h3 id="liveview-for-events" tabindex="-1">Liveview for Events <a class="header-anchor" href="#liveview-for-events" aria-label="Permalink to &quot;Liveview for Events&quot;">​</a></h3><ol><li>In the left-hand navigation, under <strong>Setup &amp; Testing</strong> click on <strong>Liveview</strong>.</li><li>By default, Liveview loads the <strong>Events</strong> object.</li><li>Using the filter in the upper-left hand corner, choose the event type you want to view. This allows you to find your test click and/or resulting app download.</li><li>We recommend adding additional filters - Device ID and/or Ad Partner and/or Campaign Name - to help you more quickly identify the ad link you’re testing.</li><li>Click <strong>Update Session</strong> to view new selection.</li></ol><h4 id="liveview-for-webhooks-postbacks" tabindex="-1">Liveview for Webhooks/Postbacks <a class="header-anchor" href="#liveview-for-webhooks-postbacks" aria-label="Permalink to &quot;Liveview for Webhooks/Postbacks&quot;">​</a></h4><ol><li>In the left-hand navigation, under <strong>Setup &amp; Testing</strong> click on <strong>Liveview</strong>.</li><li>Click the <strong>Webhooks Record</strong> tab to load the Webhook/Postbacks object.</li><li>Click the <strong>Add Filter</strong> button, and select <strong>Webhook Partner Key</strong> from the drop-down and insert the relevant value for the partner.</li><li>Click the columns button to add both the <strong>Webhook Response Code</strong> and <strong>Webhook Response Body</strong> as columns.</li><li>Click <strong>Update Session</strong> to view the filtered results.</li></ol><h4 id="what-to-look-for-when-validating" tabindex="-1">What to Look For When Validating <a class="header-anchor" href="#what-to-look-for-when-validating" aria-label="Permalink to &quot;What to Look For When Validating&quot;">​</a></h4><ul><li>Check the expected macros are populated AND the response code. Most importantly, you&#39;ll want to verify the IDFA/AAID and the Click ID are populated.</li><li>We recommend verifying the event with the ad partner even when the Response Code is 200 (successful). To do so, send them the event name, the webhook request URL, device ID, timestamp, webhook response code and webhook response body.</li><li>If you can’t find the webhook you’re looking for, we recommend testing your ad link several more times to trigger the subsequent webhook/postback.</li></ul><h4 id="how-to-find-a-partner-s-webhook-key" tabindex="-1">How to Find a Partner’s Webhook Key <a class="header-anchor" href="#how-to-find-a-partner-s-webhook-key" aria-label="Permalink to &quot;How to Find a Partner’s Webhook Key&quot;">​</a></h4><p>In order to filter the webhook records by partner to validate the postback is firing correctly, you need to find the partner’s webhook key.</p><p>To find the partner’s webhook key:</p><ol><li>In the left-hand navigation, under <strong>Channels &amp; Links</strong>, click <strong>Ads</strong> and then <strong>Partner Management</strong>.</li><li>Search for the corresponding partner and click on it to select it.</li><li>Once the partner is selected and you’re viewing the <strong>AdPartner Settings</strong> page, look to the URL window of your browser where you will find the URL of the current Branch dashboard page.</li><li>The partner webhook key is the first parameter after <code>/partner-management/</code> and begins with <code>a_</code>; e.g. <code>a_youappi</code>.</li></ol>',38)])])}const m=t(r,[["render",n]]);export{u as __pageData,m as default};
